import React, { useState } from "react";
import Login from "./Login";
import ChatPage from "./ChatPage";
import CallWindow from "./CallWindow";
import io from "socket.io-client";
import FriendsList from "./FriendsList"; // 👈 add this

const socket = io("http://localhost:3001");

export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [friend, setFriend] = useState(null);
  const [inCall, setInCall] = useState(false);

if (!currentUser) return <Login onLogin={setCurrentUser} />;

if (inCall && friend) {
  return <CallWindow currentUser={currentUser} friend={friend} socket={socket} onEnd={() => setInCall(false)} />;
}

if (friend) {
  return <ChatPage currentUser={currentUser} friend={friend} onBack={() => setFriend(null)} onCall={() => setInCall(true)} />;
}

// 👇 show friends list after login
return <FriendsList currentUser={currentUser} onSelectFriend={setFriend} />;


  if (inCall && friend) {
    return (
      <CallWindow
        currentUser={currentUser}
        friend={friend}
        socket={socket}
        onEnd={() => setInCall(false)}
      />
    );
  }

  if (friend) {
    return (
      <ChatPage
        currentUser={currentUser}
        friend={friend}
        onBack={() => setFriend(null)}
        onCall={() => setInCall(true)}
      />
    );
  }

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>Welcome {currentUser.userId}</h2>
      <input
        style={styles.input}
        placeholder="Enter friend userId"
        onChange={(e) => setFriend({ userId: e.target.value })}
      />
      <button style={styles.button} onClick={() => setFriend(friend)}>Start Chat</button>
    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    maxWidth: 300,
    margin: "50px auto",
    padding: 20,
    border: "1px solid #ccc",
    borderRadius: 10,
    backgroundColor: "#f9f9f9",
  },
  title: {
    textAlign: "center",
    marginBottom: 20,
    fontFamily: "Arial, sans-serif",
  },
  input: {
    marginBottom: 10,
    padding: 10,
    fontSize: 16,
    borderRadius: 5,
    border: "1px solid #ccc",
  },
  button: {
    padding: 10,
    fontSize: 16,
    borderRadius: 5,
    border: "none",
    backgroundColor: "#25D366", // WhatsApp green
    color: "white",
    cursor: "pointer",
  },
};
